use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct IpAddressRecord {
    ip: String,
}

fn main() -> io::Result<()> {
    let file_path = "network_log.txt";

    std::fs::write(file_path, "192.168.1.1:okn10.0.0.5:badn192.168.2.50:oknreserved data starts heren192.168.3.1:ok");

    let file = File::open(file_path)?;
    let reader = BufReader::new(file);

    let mut lines = reader.lines();

    let result: Vec<IpAddressRecord> = lines
        .take_while(|line_result| { 
            match line_result { 
                Ok(line) => !line.contains("reserved"), 
                Err(_) => false, 
            }
        })
        .filter_map(|line_result| {
            let line = match line_result { 
                Ok(l) => l, 
                Err(_) => return None,
            };
            if line.starts_with("192.168.") {
                Some(IpAddressRecord { ip: line.split(':').next().unwrap().to_string() }) 
            } else {
                None
            }
        }) 
        .collect();

    println!("Processed records:");
    for record in result {
        println!("Found IP: {}", record.ip);
    }

    Ok(())
}

use std::io::{self};

struct ConfigRecord {
    id: u32,
    status: String,
    data: Vec<u8>,
}

fn main() -> io::Result<()>{
    let records = vec![
        ConfigRecord { id: 101, status: "pending".to_string(), data: vec![0xAA] },
        ConfigRecord { id: 102, status: "pending".to_string(), data: vec![0xBB] },
        ConfigRecord { id: 103, status: "processed".to_string(), data: vec![0xCC] },
        ConfigRecord { id: 104, status: "failed".to_string(), data: vec![0xDD] },
        ConfigRecord { id: 105, status: "pending".to_string(), data: vec![0xEE] },
        ConfigRecord { id: 106, status: "unknown".to_string(), data: vec![0xFF] },
        ConfigRecord { id: 107, status: "ok".to_string(), data: vec![0x11] },
    ];

    let initial_process = records.iter().take_while(|r| r.status == "pending").count();
    println!("Processed {} records in the initial pending phase.", initial_process);

    let filtered_stream = records.into_iter()
        .skip_while(|r| r.status != "ok".to_string() && r.id < 107)
        .collect::<Vec<_>>().into_iter();

    let final_count = filtered_stream.take_while(|r| r.data[0] != 0xFF).count();
    println!("Found {} records after skipping initial bad states.", final_count);

    Ok(())
}

use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct LogEntry {
    line: String,
    is_commit: bool,
}

fn analyze_log_file(path: &str) -> io::Result<Vec<LogEntry>> {
    let file = File::open(path)?;
    let reader = BufReader::new(file);

    let mut entries = Vec::new();
    for line in reader.lines() {
        let s = line?;
        if s.contains("commit") {
            entries.push(LogEntry { line: s, is_commit: true });
        } else if !s.is_empty() && entries.iter().any(|e| e.is_commit) {
            let last_entry = entries.last().unwrap();
            if last_entry.is_commit && !s.contains("Processed") {
                entries.push(LogEntry { line: s, is_commit: false });
            }
        }
    }
    Ok(entries)
}

fn main() -> io::Result<()> {
    let log_path = "test_log.txt";
    println!("Analyzing logs from {}", log_path);

    if let Ok(mut entries) = analyze_log_file(log_path) {
        let filtered: Vec<String> = entries.into_iter()
            .take_while(|e| e.is_commit || !e.line.contains("Skipped"))
            .map(|e| e.line)
            .collect();

        println!("n--- Processed Commit Markers ---");
        for line in filtered {
            print!("{}
", line);
        }
    }
    Ok(())
}

use std::collections::VecDeque;

struct TelemetryRecord {
    timestamp: u64,
    value: f64,
}

fn process_sensor_stream(data: Vec<f64>) -> (Vec<TelemetryRecord>, Vec<TelemetryRecord>)
{
    let mut good_records = VecDeque::new();
    let mut bad_records = VecDeque::new();

    let initial_threshold: f64 = 0.1;
    let stop_threshold: f64 = -999.0;

    let first_good_iter = data.into_iter().skip_while(|&v| v.abs() < initial_threshold).collect::<Vec<f64>>();

    for (i, &value) in first_good_iter.iter().enumerate() {
        if value >= stop_threshold && value > 0.0 {
            let record = TelemetryRecord { timestamp: 1672531200 + i as u64, value };
            good_records.push_back(record);
        } else if value < stop_threshold {
            bad_records.push_back(TelemetryRecord { timestamp: 0, value });
            break;
        }
    }

    let final_result = good_records.into_iter().map(|r| TelemetryRecord { timestamp: r.timestamp, value: r.value }).collect();
    let remaining_bad = bad_records.into_iter().map(|r| TelemetryRecord { timestamp: r.timestamp, value: r.value }).collect();

    (final_result, remaining_bad)
}

fn main() {
    let stream_data = vec![-999.0, 0.05, 0.12, 0.15, 0.30, 0.22, -999.0];
    let (ok, bad) = process_sensor_stream(stream_data);

    println!("Successfully processed records: {}", ok.len());
    for record in &ok {
        println!("Time: {}, Value: {:.2}", record.timestamp, record.value);
    }

    println!("
Skipped/Bad records count: {}", bad.len());
}

use std::collections::HashMap;

struct UserRecord {
    id: u32,
    isActive: bool,
    data: String,
}

fn filter_and_skip_users(records: Vec<UserRecord>) -> Vec<String> {
    let initial_data = records.into_iter().collect::<Vec<UserRecord>>();

    let skipped_iterator = initial_data.iter().skip_while(|record| !record.isActive);

    let processed_iterator = skipped_iterator.take_while(|record| record.id % 3 != 0);

    processed_iterator.map(|record| format!("Processed data for user ID: {}", record.id)).collect()
}
